head.script:
/**
 * 화 면 명 : (매출)Sea, Air Freight 일괄 등록
 * 메뉴경로 : 국제물류/Accounting/
 * ASIS경로 : /dongwon-debis-engine/src/main/webapp/il/acc/acetc/ac_111_01_02b.jsp
 * 작 성 자 : 이진우
 * 작 업 일 : 2026-03-19
 * 작업내용 :
 *    1. 화면세팅
 *    2. 초기세팅(UDC), 그리드(데이터리스트)
 *    3. 스크립트 TOBE전환
 *    4. 기능확인(버튼)
 * 참고사항

 * 수정이력 :
 *    - 2026-03-19      이진우    최초작성
 *  se_201_01_02b(Import House B/L Freight 서지수)
 */
scwin.strCurDate = WebSquare.date.getCurrentServerDate();  // 서버를 기준으로 현재 날짜 반환
scwin.strCuYm = "";

scwin.flag = false; // 저장 가능 flag
scwin.editFlag = false; // 수정 여부. false = 수정 전. true = 수정 후
scwin.columnNum = 17; // 열 개수 저장하는 변수
scwin.iii = -1;

scwin.hd_kcomcd = "DBEX";

/**
 * TOBE : 초기로드(UDC 있으면 scwin.onUdcCompleted 초기값 세팅)
 */
scwin.onpageload = function() {
	//f_Header(); // 헤더 초기화
	dma_searchCloseYm.setEmptyValue();
    dma_searchCloseYm.set("coCd", "000"); // 동원로엑스 회사 코드

    //tr_getMaxCloseYm.Post(); // 마감년월조회
    $c.sbm.execute(sbm_getMaxCloseYm);

	$c.gus.cfEnableObjects();

    gr_freightListcnt.setStyle("display", "none");

};

// 회계마감 여부를 체크하는 함수 : 회계마감된 월로는  실적일자, Billing Date 입력 불가능
scwin.f_JobCloseYn = function (date) {
    date = date.substr(0,6);

	// 이미 마감된 월
	if (ds_getMaxCloseYm.getCellData(0, "closeYm") > date) {
		return -1; // 불가
	}
	else if (ds_getMaxCloseYm.getCellData(0, "closeYm") < date) {
		return 0; // 알림
	}
	else {
		return 1; // 정상
	}
};

// CSV 업로드 파일 검사(ds_freightList)
scwin.f_CsvValidation = async function () {
	// csv 파일 열이 0개 일때 오류 반환
	if (ds_csv.getRowCount() == 0) {
		await $c.gus.cfAlertMsg(MSG_CM_ERR_003);
		return false;
	}

	// 행 개수 세기
	let cntRow = ds_csv.getRowCount();

	// 각 행 돌기
	for(var i=0; i < ds_csv.getRowCount(); i++) {
		// 모든 열 비어있는지 확인 (수동으로 행 개수 세기)
		let colcnt = 0;
		for (var v=0; v < ds_csv.getColumnCount(); v++) {
			if (ds_csv.getCellData(i, ds_csv.getColumnID(v)) == null || ds_csv.getCellData(i, ds_csv.getColumnID(v)) == '') {
				colcnt += 1;
			}
		}
		if (colcnt == scwin.columnNum) {
			cntRow = i-1;
			break;
		}

		let err = "";
		// 파트너 여부 체크
		let partner = new String();
// 		partner = ds_csv.NameValue(i, ds_csv.ColumnID(3));
// 		if (partner == null) {
// 			partner = '';
// 			ds_csv.NameValue(i, ds_csv.ColumnID(3)) = '';
			partner = 'Y';
            ds_csv.setCellData(i, ds_csv.getColumnID(2), 'Y');
// 		}

// 		partner = partner.replace(/ /gi, "");
		let partnerYn = 'Y';
// 		var partnerYn = '';
// 		if (partner == 'Y' || partner == 'y')	partnerYn = 'Y';
// 		else if (partner == "" || partner == null)	partnerYn = 'N';
// 		else partnerYn = 'err';

		//selling 매출
        ds_csv.setCellData(i, ds_csv.getColumnID(3), 'D');

		// 내부거래 여부 체크
		let customerCode = new String();
		customerCode = ds_csv.getCellData(i, ds_csv.getColumnID(5));
		if (customerCode == null) {
			customerCode = '';
			ds_csv.setCellData(i, ds_csv.getColumnID(5), '');
		}

		customerCode = customerCode.replace(/ /gi, "");
// 		var innerYn = false;
// 		if (customerCode == '109856' || customerCode == '내부' || customerCode == '내부거래' || customerCode.toUpperCase() == 'INTERNAL') {
// 			innerYn = true;
// 		}

// 		if (innerYn && partnerYn == 'Y') {
// 			err += "파트너인 경우, 내부거래 코드가 올 수 없습니다.";
// 		}

        console.log("for문 시작");
        console.log("ds_csv.getColumnCount():", ds_csv.getColumnCount());

		// 각 열 돌기
        for(var k=0; k < ds_csv.getColumnCount(); k++) {
// 			alert(ds_csv.getColumnID(k));
			// 모든 항 ' ',쉼표 제거
			let temp = new String();
			temp = ds_csv.getCellData(i, ds_csv.getColumnID(k));
			if (temp == null) {
				ds_csv.setCellData(i, ds_csv.getColumnID(k), '');
				temp = '';
			}
			temp = temp.replace(/ /gi, "");
			temp = temp.replace(/,/gi, "");
			temp = temp.toUpperCase(); // 대문자 처리
			ds_csv.setCellData(i, ds_csv.getColumnID(k), temp);

			switch (k) {
			case 0: // SEA/AIR
				if ( temp == '' || !(/^[SA]{1}$/.test(temp)) ) {
					err += "'SEA/AIR'열에는 S나 A를 입력해주세요. ";
				}
				break;
			case 1: // EXP/IMP
				if (temp == '' || !(/^[IE]{1}$/.test(temp)) ) {
					err += "'EXP/IMP'열에는 I나 E를 입력해주세요. ";
				}
				break;
			case 2: // 파트너
// 				if (partnerYn == 'err') {
// 					err += "'파트너'열에는 파트너일 경우 Y, 아닐 경우 공백으로 입력해주세요. ";
// 				}
				break;
			case 3: // C/D
// 				if ( (partnerYn == 'Y' && !(/^[CD]{1}$/.test(temp)) ) || (partnerYn == 'N' &&  temp != '') ) {
// 					err += "'C/D'열에는 파트너일 경우 C나 D, 아닐 경우 공백으로 입력해주세요. ";
// 				}
				break;
			case 4: // House B/L
				if ( temp == '' ) {
					err += "House B/L을 입력해주세요. ";
				}
				break;
			case 5: // Customer Code
				if ( temp == '' ) {
					err += "Customer Code를 입력해주세요. ";
				}
				break;
			case 6: // Freight Code
				if ( temp == '' ) {
					err += "Freight Code를 입력해주세요. ";
				}
// 				else if ( innerYn && (temp.charAt(temp.length-1) == 'V' || temp.charAt(temp.length-1) == 'K' ) ) {
// 					err += "내부거래일 경우, 운임코드에 -V, -K의 코드는 올 수 없습니다. ";
// 				}
				else if ( partnerYn != 'Y' && ds_csv.getCellData(i, ds_csv.getColumnID(7)) != '' 
						&& ds_csv.getCellData(i, ds_csv.getColumnID(7)) != 'KRW'	&& (ds_csv.getCellData(i, ds_csv.getColumnID(14)) == 'Y')) {
					var c = temp.charAt(temp.length-1);
					if (c == 'J' || c == 'V' || c == 'K') {
						err += "CUR이 KRW가 아니며 외화정산이 Y일 경우, 운임코드에 -J, -V, -K의 코드는 올 수 없습니다. ";
					}
				}
				break;
			case 7: // CUR
				if ( temp == '' ) {
					err += "CUR를 입력해주세요. ";
				}
				break;
			case 8: // Amount  
				if ( isNaN(temp) ) {
					err += "'Amount'열은 숫자나 공백으로 입력해주세요. ";
				}
				break;
			case 9: // EX-RATE
				if ( isNaN(temp) ) {
					err += "'Ex-rate'열은 숫자나 공백으로 입력해주세요. ";
				}
				break;
			case 10: // Amount(원)
				if ( isNaN(temp) ) {
					err += "'Amount(원)'열은 숫자나 공백으로 입력해주세요. ";
				}
				break;
			case 11: // VAT
				if ( isNaN(temp) ) {
					err += "'VAT'열은 숫자나 공백으로 입력해주세요. ";
				}
				if(String(ds_csv.getCellData(i, ds_csv.getColumnID(6))).charAt(String(ds_csv.getCellData(i, ds_csv.getColumnID(6))).length-1) == 'V'){
// 					ds_csv.getCellData(i, "vat", ds_csv.getCellData(i, "amount") * 0.1);
					ds_csv.setCellData(i, ds_csv.getColumnID(11), ds_csv.getCellData(i, ds_csv.getColumnID(10)) * 0.1);
				}
				break;                
			case 12: // Result Date
				if ( temp == '' || isNaN(temp) || temp.length != 8 ) {
					err += "'Result Date'열은 날짜로 입력해주세요. ";
				}
				else if ( scwin.f_JobCloseYn(temp) == -1 ) {
					err += "'Result Date'의 날짜는 결산이 완료된 과거로 설정될 수 없습니다. ";
				}
				break;
			case 13: // Invoice 쪽 billing Date
// 				if ( temp == '' || isNaN(temp) || temp.length != 8) {
// 					err += "'Invoice Date'열은 날짜로 입력해주세요. ";
// 				}
// 				else if ( scwin.f_JobCloseYn(temp) == -1 ) {
// 					err += "'Invoice Date'의 날짜는 결산이 완료된 과거로 설정될 수 없습니다. ";
// 				}
				break;
			case 14: // 외화 정산 -> Partner의 경우 모두 Y
				if (partnerYn == 'N' && (temp != '' && temp != 'Y')) {
					err += "'외화 정산'열은 Y나 공백으로 입력해주세요. ";
				}
				break;
			case 15: // 내부거래 코드
// 				if (innerYn) {
// 					if (temp == '') {
// 						err += "내부거래 코드를 입력해주세요. ";
// 					}
// 				}
// 				else {
// 					if (temp != '') {
// 						err += "Customer Code가 '109856'일 경우에만 내부거래 코드를 입력할 수 있습니다. ";
// 					}
// 				}
				break;
			case 16: // 요청범위
// 				if (!innerYn) { // 내부거래가 아닐 때만 검사
					if (temp == '') {
						err += "'요청범위'를 입력해주세요. (1~2) ";
					}
					else if (temp != '1' && temp != '2') {
						err += "'요청범위'는 1~2 사이의 숫자를 입력해주세요. ";
					}else if (temp == '2') {
						if ( ds_csv.getCellData(i,ds_csv.getColumnID(13)) == '' || isNaN(ds_csv.getCellData(i,ds_csv.getColumnID(13))) || 
                        String(ds_csv.getCellData(i,ds_csv.getColumnID(13))).length != 8) {
		 					err += "'Invoice Date'열은 날짜로 입력해주세요. ";
		 				}
		 				else if ( scwin.f_JobCloseYn(ds_csv.getCellData(i,ds_csv.getColumnID(13))) == -1 ) {
		 					err += "'Invoice Date'의 날짜는 결산이 완료된 과거로 설정될 수 없습니다. ";
		 				}
					}

// 				}
				break;
			} //switch 끝
		}//열끝

		// ds_err.AddRow();
        ds_err.insertRow();
        ds_err.setCellData(i, "err", err);

        scwin.iii = i;

		if (err == '') { // 에러 없을 시 DB 유효값 조회
// 			if (innerYn) { //내부거래일 때 109856으로 값 바꿔주기.
// 				ds_csv.NameValue(i, ds_csv.ColumnID(6)) = '109856';
// 				ds_csv.NameValue(i, ds_csv.ColumnID(17)) = 0;
// 			}

			ds_RetrieveValidation.removeAll();
			ds_validation.removeAll();
			//ds_RetrieveValidation.ImportData(ds_csv.ExportData(i, 1, true));
            //setJSON([ ... ]): ds_RetrieveValidation에 기존 데이터를 모두 지우고, 방금 가져온 1건의 행만 배열 형태로 담아 새로 채웁니다.
            //getRowJSON(): 기본적으로 삭제된 행을 제외한 현재 화면상의 데이터만 가져옵니다.
            //getAllJSON(): 삭제(Delete) 상태인 행까지 포함하여 가져옵니다.
            ds_RetrieveValidation.setJSON([ds_csv.getRowJSON(i)]);

            console.log("에러 없을 시 ds_csv.getRowJSON()::" + JSON.stringify(ds_csv.getRowJSON(i)));

            //tr_validation.Post();
            await $c.sbm.execute(sbm_validation);

            //서브미션에서 호출 하면 멈춤, 그래서 직접 스크립트로 호출([중요]현재 for문을 다돌고 이후단 수행하기 위한 방법)
            scwin.sbm_validation_submitdone();

		}
	}//행끝

	// 완료
    //ds_freightList.ImportData(ds_csv.ExportData(1, cntRow, true));
    for(var i=0; i < cntRow; i++) {
        //ds_freightList.ImportData(ds_freightList.ExportData(1, cntRow, true));
        //ds_csv의 i번째 행 데이터 1건을 추출하여 ds_freightList의 기존 데이터 뒤에 추가(Append)하는 가장 효율적인 방식입니다.
        ds_freightList.setJSON([ds_csv.getRowJSON(i)],true);
    }

	for (var k=0; k < ds_freightList.getRowCount(); k++) {
		ds_freightList.setCellData(k, "err", ds_err.getCellData(k, "err"));
	}

	ds_err.removeAll();
	return true;
};

scwin.sbm_validation_submitdone = function (e) {

    let validationrowCnt = ds_validation.getRowCount();

	let arr = ["blNo", "custCd", "freightCd", "crcCd", "innerDept"];
	let arrMsg = ["House B/L", "Customer Code", "Freight Code", "CUR Code", "내부거래 코드"];

	let msg = "";

    console.log("validationrowCnt:처음:", validationrowCnt);

    if (validationrowCnt > 0) {

        for (let i=0; i < arr.length; i++) {
            if (ds_validation.getCellData(0, arr[i]) != '1') {
                msg += arrMsg[i] + " 항목이 유효하지 않습니다. ";
            }
        }

        console.log("msgmsg:" + msg);
        console.log("scwin.iii:" + scwin.iii);

        ds_err.setCellData(scwin.iii, "err", msg); //for문 i인텍스 전역변수(scwin.iii)로 넘겨줌

    }else if(validationrowCnt == 0) {
        console.log("validationrowCnt:00:", validationrowCnt);
    }else {
        console.log("validationrowCnt::", validationrowCnt);
        scwin.sbm_validation_submiterror();
    }

};

//todo submiterror는 리턴이 없으므로 submitdone에서 처리 해주어야 함
scwin.sbm_validation_submiterror = function () {
    //cfShowError(this); tobe미사용
    scwin.f_DsClear();
    ds_csv.removeAll();

};

// 데이터셋 한번에 클리어
scwin.f_DsClear = function () {
	ds_freightList.removeAll();
	// ds_freightListcnt.removeAll();
	ds_RetrieveValidation.removeAll();
	ds_validation.removeAll();
	ds_err.removeAll();

	ds_seaImpPartner.removeAll();
	ds_seaImpBuying.removeAll();
	ds_seaExpPartner.removeAll();
	ds_seaExpBuying.removeAll();
	ds_airImpPartner.removeAll();
	ds_airImpBuying.removeAll();
	ds_airExpPartner.removeAll();
	ds_airExpBuying.removeAll();
	ds_dbCodeList.removeAll();
	ds_dbCodeRetrieve.removeAll();
	ds_dbCodeResult.removeAll();
	ds_invoiceSIP.removeAll();
	ds_invoiceSIB.removeAll();
	ds_invoiceSEP.removeAll();
	ds_invoiceSEB.removeAll();
	ds_invoiceAIP.removeAll();
	ds_invoiceAIB.removeAll();
	ds_invoiceAEP.removeAll();
	ds_invoiceAEB.removeAll();
	//cfShowTotalRows(totalRows, 0);
    txt_totalRows.setValue(0);
};

// CSV 업로드 함수
// function f_Upload() {
scwin.f_Import = async function () {
    ////
    //재업로드시 기존 데이타 삭제
    ds_csv.removeAll();

    console.log("ds_freightListcnt cnt::", ds_freightListcnt.getRowCount());

    //ds_freightListcnt에 1번째 부터 ds_csv 에 담기
    for(let i=0; i < ds_freightListcnt.getRowCount(); i++) {
        if(i > 0) {
            ds_csv.setJSON([ds_freightListcnt.getRowJSON(i)],true);
            console.log("ds_freightListcnt::" + JSON.stringify(ds_freightListcnt.getRowJSON(i)));
        } 
    }

    ///
	scwin.f_DsClear();

	scwin.flag = false;

	$c.gus.cfProgressWinClose();
	if (await scwin.f_CsvValidation()) {
        //tobe 추가
        // gr_freightList.refreshRow(); //색깔 적용 현행화 [그리드 UI만 다시 그려야 할 때 (드문 케이스)]
        ds_freightList.modifyAllStatus("C");

        txt_totalRows.setValue(ds_freightList.getRowCount());
        await $c.gus.cfAlertMsg("업로드 완료");
	}
	else {
        txt_totalRows.setValue(0);
	}

    await scwin.f_ErrCheck();

};

// 에러 체크 함수
scwin.f_ErrCheck = async function () {
	for (var i=0; i < ds_freightList.getRowCount(); i++) {
		if (ds_freightList.getCellData(i, "err") != "") {
			scwin.flag = false;
			return;
		}
	}
	scwin.flag = true;

    return;

};

// 최종 실행 함수 (저장 버튼)
scwin.f_Save = async function () {
	if (scwin.editFlag) {
		await $c.gus.cfAlertMsg("수정한 값이 존재합니다. 재검증 버튼을 눌러 재검증을 해주세요.");
		return;
	}
	//if (!ds_freightList.IsUpdated) {
    if (!ds_freightList.getModifiedIndex().length > 0) {
		await $c.gus.cfAlertMsg("변경된 내역이 없습니다. 업로드 후 저장해주세요.");
		return;
	}
	if (!scwin.flag) {
		await $c.gus.cfAlertMsg("수정되지 않은 오류 내역이 있습니다. '오류'열을 확인하고, 수정 후 재업로드 해주세요.");
		return;
	}

	// if (!cfConfirmMsg("저장하시겠습니까?")) {
    ret = await $c.win.confirm(MSG_CM_CRM_001);
    if(ret == false){
        return;
    }

	// 1. DB 값 받아오기
    for (var i=0; i < ds_freightList.getRowCount(); i++) {

        ds_dbCodeRetrieve.removeAll();
        //ds_dbCodeRetrieve.ImportData(ds_freightList.ExportData(i, 1, true));
        ds_dbCodeRetrieve.setJSON([ds_freightList.getRowJSON(i)]);

        console.log("ds_freightList.getRowJSON()::" + JSON.stringify(ds_freightList.getRowJSON(i)));
        console.log("ds_dbCodeRetrieve.getRowJSON()::" + JSON.stringify([ds_dbCodeRetrieve.getRowJSON(0)]));
        console.log("ds_dbCodeRetrieve.getRowJSON():,,:", ds_dbCodeRetrieve.getRowJSON(0));

        await $c.sbm.execute(sbm_dbCodeRetrieve); //await 걸면 멈춤, 함수호출 방식으로 변경

        scwin.sbm_dbCodeRetrieve_submitdone(); //ev:submitdone 제거후 호출해야 에러 없음,직접 스크립트로 호출([중요]현재 for문을 다돌고 이후단 수행하기 위한 방법)

    }

	// 2. 각 데이터에 맞는 데이터셋으로 옮기기
	for (var i=0; i < ds_freightList.getRowCount(); i++) {
		let SA = ds_freightList.getCellData(i, "seaAirCls");
		let IE = ds_freightList.getCellData(i, "expImp");
		// let P = ds_freightList.getCellData(i, "partner");
		let P = "Y";

		let temp; // 임시 데이터셋 자리
		let tempInv; // 임시 데이터셋 자리2
		if (SA == 'S') { // 해운
			if (IE == 'I') { // Import
				if (P == 'Y') {
					temp = ds_seaImpPartner;
					tempInv = ds_invoiceSIP;
				}
				else {
					temp = ds_seaImpBuying;
					tempInv = ds_invoiceSIB;
				}
			}
			else { // Export
				if (P == 'Y') {
					temp = ds_seaExpPartner;
					tempInv = ds_invoiceSEP;
				}
				else {
					temp = ds_seaExpBuying;
					tempInv = ds_invoiceSEB;
				}
			}
		}
		else { // 항공
			if (IE == 'I') { // Import
				if (P == 'Y') {
					temp = ds_airImpPartner;
					tempInv = ds_invoiceAIP;
				}
				else {
					temp = ds_airImpBuying;
					tempInv = ds_invoiceAIB;
				}
			}
			else { // Export
				if (P == 'Y') {
					temp = ds_airExpPartner;
					tempInv = ds_invoiceAEP;
				}
				else {
					temp = ds_airExpBuying;
					tempInv = ds_invoiceAEB;
				}
			}
		}

		//temp.AddRow();
        temp.insertRow();
		temp.setCellData(temp.getRowCount()-1, "odrNo", ds_dbCodeList.getCellData(i, "odrNo"));
		temp.setCellData(temp.getRowCount()-1, "kcomcd", ds_dbCodeList.getCellData(i, "kcomcd"));
		temp.setCellData(temp.getRowCount()-1, "seaAirCls", SA);
		temp.setCellData(temp.getRowCount()-1, "blNo", ds_freightList.getCellData(i, "blNo"));
		temp.setCellData(temp.getRowCount()-1, "mhno", ds_dbCodeList.getCellData(i, "mhno"));
		temp.setCellData(temp.getRowCount()-1, "fareEngCd", ds_freightList.getCellData(i, "freightCd"));
		temp.setCellData(temp.getRowCount()-1, "fareEngNm", ds_dbCodeList.getCellData(i, "fareEngNm"));
		temp.setCellData(temp.getRowCount()-1, "fareGrpCd", ds_dbCodeList.getCellData(i, "fareGrpCd"));

        if (SA == 'S') {
            temp.setCellData(temp.getRowCount()-1, "fareUnit", 'CASE');
        }else {
            temp.setCellData(temp.getRowCount()-1, "fareUnit", '');
        }
		//temp.setCellData(temp.getRowCount(), "locPtnCls", P) == 'Y' ? '2' : '1';
        temp.setCellData(temp.getRowCount()-1, "locPtnCls", "1");	//selling locPtnCls 1
		temp.setCellData(temp.getRowCount()-1, "mblHblCls", "H");

		// temp.setCellData(temp.getRowCount(), "drcrCls", P) == 'Y' ? ds_freightList.getCellData(i, "cd") : 'C';
        temp.setCellData(temp.getRowCount()-1, "drcrCls", "D");	//selling drcrCls D

        if (SA == 'S') {
            temp.setCellData(temp.getRowCount()-1, "ppccCls", ds_dbCodeList.getCellData(i, "ppccCls"));
        }else {
            temp.setCellData(temp.getRowCount()-1, "ppccCls", '');
        }

        temp.setCellData(temp.getRowCount()-1, "crcCd", ds_freightList.getCellData(i, "crcCd"));

        if (SA == 'S') {
            temp.setCellData(temp.getRowCount()-1, "qty", 0);
        }else {
            temp.setCellData(temp.getRowCount()-1, "qty", ds_dbCodeList.getCellData(i, "qty"));
        }

        if (SA == 'S') {
            temp.setCellData(temp.getRowCount()-1, "grossWt", 0.0);
        }else {
            temp.setCellData(temp.getRowCount()-1, "grossWt", ds_dbCodeList.getCellData(i, "grossWt"));
        }

		temp.setCellData(temp.getRowCount()-1, "chgWt", 1);
		temp.setCellData(temp.getRowCount()-1, "trfUpr", 0.0);
		temp.setCellData(temp.getRowCount()-1, "exRate", ds_dbCodeList.getCellData(i, "exRate"));

        if (SA == 'S') {
            temp.setCellData(temp.getRowCount()-1, "exRateTyp", ds_dbCodeList.getCellData(i, "exRateTyp"));
        }else {
            temp.setCellData(temp.getRowCount()-1, "exRateTyp", '');
        }

		temp.setCellData(temp.getRowCount()-1, "prtnAmt", 0);
        temp.setCellData(temp.getRowCount()-1, "rsltsStdDt", ds_freightList.getCellData(i, "resultDate"));

        if (ds_freightList.getCellData(i, "vat") > 0) {
            temp.setCellData(temp.getRowCount()-1, "vatYn", 1);
        }else {
            temp.setCellData(temp.getRowCount()-1, "vatYn", 0);
        }

		// Partner
		// if (P == 'Y') {
			temp.setCellData(temp.getRowCount()-1, "sellSeq", 0);
			temp.setCellData(temp.getRowCount()-1, "bilgClntNo", ds_freightList.getCellData(i, "custCd"));
			temp.setCellData(temp.getRowCount()-1, "bilgClntNm", ds_dbCodeList.getCellData(i, "bilgClntNm"));
			temp.setCellData(temp.getRowCount()-1, "sellItemCd", ds_dbCodeList.getCellData(i, "sellItemCd"));
			temp.setCellData(temp.getRowCount()-1, "sellUpr", 1);
			temp.setCellData(temp.getRowCount()-1, "sellAmtFcrc", ds_freightList.getCellData(i, "amount"));

            if (ds_freightList.getCellData(i, "amountWon") != '') {
                temp.setCellData(temp.getRowCount()-1, "sellAmt", ds_freightList.getCellData(i, "amountWon"));
            }else {
                temp.setCellData(temp.getRowCount()-1, "sellAmt", ds_freightList.getCellData(i, "amount") * ds_freightList.getCellData(i, "exRate"));
            }

			temp.setCellData(temp.getRowCount()-1, "vatAmt", ds_freightList.getCellData(i, "vat"));

		// }
		// Buying
		// else {
		// 	temp.setCellData(temp.getRowCount(), "pchsSeq", 0);
		// 	temp.setCellData(temp.getRowCount(), "pchsClntNo", ds_freightList.getCellData(i, "custCd"));
		// 	temp.setCellData(temp.getRowCount(), "pchsClntNm", ds_dbCodeList.getCellData(i, "pchsClntNm"));
		// 	temp.setCellData(temp.getRowCount(), "selpchItemCd", ds_dbCodeList.getCellData(i, "selpchItemCd"));
		// 	temp.setCellData(temp.getRowCount(), "pchsUpr", 1);
		// 	temp.setCellData(temp.getRowCount(), "pchsAmtFcrc", ds_freightList.getCellData(i, "amount"));
		// 	temp.setCellData(temp.getRowCount(), "pchsAmt", ds_freightList.getCellData(i, "amountWon")) != '' ? 
		// 			ds_freightList.getCellData(i, "amountWon") : (ds_freightList.getCellData(i, "amount") * ds_freightList.getCellData(i, "exRate")); 
		// 	temp.setCellData(temp.getRowCount(), "vat", ds_freightList.getCellData(i, "vat"));
		// 	temp.setCellData(temp.getRowCount(), "sellDeptCd", ds_freightList.getCellData(i, "innerDept")) != '' ? ds_freightList.getCellData(i, "innerDept") : '';
		// 	temp.setCellData(temp.getRowCount(), "sellDeptNm", ds_freightList.getCellData(i, "innerDept")) != '' ? ds_dbCodeList.getCellData(i, "sellDeptNm") : '';
		// 	temp.setCellData(temp.getRowCount(), "pchsTyp", ds_freightList.getCellData(i, "innerDept")) != '' ? '3' : '1';
		// }

		// usdAmt 계산
		if (SA == 'S' && ds_dbCodeList.getCellData(i, "usdAmt") != 0) {
			if (P == 'Y') {
                temp.setCellData(temp.getRowCount()-1, "usdAmt", Math.round(( temp.getCellData(temp.getRowCount()-1, "sellAmt") / ds_dbCodeList.getCellData(i, "usdAmt") ) * 100) / 100);
            }else {
                temp.setCellData(temp.getRowCount()-1, "usdAmt", Math.round(( temp.getCellData(temp.getRowCount()-1, "pchsAmt") / ds_dbCodeList.getCellData(i, "usdAmt") ) * 100) / 100);
            }

		}

		// qty, grossWt 추가 계산
		if (SA == 'A' && IE == 'E' && P == 'Y') {
			temp.setCellData(temp.getRowCount()-1, "qty", 0);
			temp.setCellData(temp.getRowCount()-1, "grossWt", 0);
		}

		// Invoice 생성 관련 ds 설정
        //tempInv.ImportData(...): 추출된 1건의 데이터를 tempInv DataList에 넣습니다. (기본적으로 기존 데이터 뒤에 Append 됩니다.)
		// tempInv.ImportData(temp.ExportData(temp.CountRow, 1, true));
        tempInv.insertRow(); //asis는 addrow가 없어도 수행됨, 그래서 tobe 추가됨
        tempInv.setJSON([temp.getRowJSON(temp.getRowCount()-1)]);

        console.log("temptemp getID:",temp.getID());
        console.log("tempInvtempInv getID:",tempInv.getID());

        console.log("temp.getRowJSON()::" + JSON.stringify(temp.getRowJSON(temp.getRowCount()-1)));

		tempInv.setCellData(tempInv.getRowCount()-1, "billingDate", ds_freightList.getCellData(i, "billingDate"));
		tempInv.setCellData(tempInv.getRowCount()-1, "foreignCurSet", ds_freightList.getCellData(i, "foreignCurSet"));
		tempInv.setCellData(tempInv.getRowCount()-1, "requestSize", ds_freightList.getCellData(i, "requestSize"));
		tempInv.setCellData(tempInv.getRowCount()-1, "partner", P);

        if (IE == 'I') {
            tempInv.setCellData(tempInv.getRowCount()-1, "expImp", 'I');
        }else {
            tempInv.setCellData(tempInv.getRowCount()-1, "expImp", 'O');
        }

		//ac_111_01_02b 여기서 추가됨
        if("Y" != tempInv.getCellData(tempInv.getRowCount()-1, "foreignCurSet")){
			tempInv.setCellData(tempInv.getRowCount()-1, "crcCd", "KRW");	
		}

        console.log("tempInv.getAllJSON()::" + JSON.stringify([tempInv.getAllJSON(temp.getRowCount()-1)])); 

	}// ds 설정 끝

	// 3. tr 실행
	//tr_saveFreight.Post();
    $c.sbm.execute(sbm_saveFreight);

};

