scwin.sbm_saveFreight_submitdone = function (e) {

    if (e.responseJSON.resultDataSet[0].Msg == "FAIL") {
        // Common submission callback already shows the server message.
        scwin.sbm_saveFreight_submiterror();
        return;
    } 
    $c.gus.cfAlertMsg(MSG_CM_INF_001);
    ds_freightList_complete.removeAll();
    for(var i=0; i < ds_freightList.getRowCount(); i++) {
        ds_freightList_complete.setJSON([ds_freightList.getRowJSON(i)],true);
    }
    txt_totalResultRows.setValue(ds_freightList_complete.getRowCount());
    scwin.f_DsClear();

};    

