//event="OnExit(row, colid, olddata)
scwin.gr_freightList_onviewchange = function (info) {
    let row = info.rowIndex; // 행 인덱스
    let col = info.colId;    // 컬럼 ID
    let oVal = info.oldValue; // 변경되기 전값
    //let nVal = info.newValue; // 변경된 값

    if (ds_freightList.getCellData(row, col) != oVal) {
		scwin.flag = false;
		scwin.editFlag = true;
	};

};

scwin.gr_freightList_complete_oncelldblclick = function (rowIndex, columnIndex, columnId) {
        if(rowIndex >= 0) {
            //해운
            if (ds_freightList_complete.getCellData(rowIndex, "seaAirCls") == "S") {
                // Import
                if (ds_freightList_complete.getCellData(rowIndex, "expImp") == "I") {
                    // var strPath = "/il/seainb/sibl/se_201_01_03b.jsp?linkcheck=2&kcomcd=DBEX&blno="
                    //         + ds_freightList_complete.getCellData(rowIndex, "blNo");
                    let strPath = "/ui/il/seainb/sibl/se_201_01_03b.xml";
                    var param = {
                        linkcheck : "2",
                        kcomcd : scwin.hd_kcomcd,
                        blno : ds_freightList_complete.getCellData(rowIndex, "blNo")
                    };

                    console.log("해운 Import param::",param);

                    // cfTabMenuUpdate( strPath , "Import House B/L (New)");
                    $c.win.openMenu("Import House B/L (New)", strPath,"se_201_01_03b.jsp",param);

                }
                // Export
                else {
                    // let strPath = "/il/seaout/sobl/se_105_01_05b.jsp?linkcheck=2&kcomcd=DBEX&blno="
                    //         + ds_freightList_complete.getCellData(rowIndex, "blNo");
                    let strPath = "/ui/il/seaout/sobl/se_105_01_05b.xml";
                    var param = {
                        linkcheck : "2",
                        kcomcd : scwin.hd_kcomcd,
                        blno : ds_freightList_complete.getCellData(rowIndex, "blNo")
                    };

                    console.log("해운 Export param::",param);

                    // cfTabMenuUpdate( strPath , "Export House B/L (New)");
                    $c.win.openMenu("Export House B/L (New)", strPath,"se_105_01_05b.jsp",param);

                }
            }

		//항공
		else {
			// Import
			if (ds_freightList_complete.getCellData(rowIndex, "expImp") == "I") {
				// var strPath = "/il/airinb/aibl/ar_203_01_03b.jsp?kcomcd=DBEX&blno="
				// 		+ ds_freightList_complete.NameValue(rowIndex, "blNo");
                let strPath = "/ui/il/airinb/aibl/ar_203_01_03b.xml";
                var param = {
                    kcomcd : scwin.hd_kcomcd,
                    blno : ds_freightList_complete.getCellData(rowIndex, "blNo")
                };

                console.log("항공 Import param::",param);

				// cfTabMenuUpdate( strPath ,"Import House B/L (New)");
                $c.win.openMenu("Import House B/L (New)", strPath,"ar_203_01_03b.jsp",param);                

			}

			// Export
			else {
				// var strPath = "/il/airout/aobl/ar_104_01_06b.jsp?kcomcd=DBEX&blno="
				// 		+ ds_freightList_complete.NameValue(rowIndex, "blNo");
                let strPath = "/ui/il/airout/aobl/ar_104_01_06b.xml";
                var param = {
                    kcomcd : scwin.hd_kcomcd,
                    blno : ds_freightList_complete.getCellData(rowIndex, "blNo")
                };

                console.log("항공 Export param::",param);

				// cfTabMenuUpdate( strPath ,"Export House B/L (New)");
                $c.win.openMenu("Export House B/L (New)", strPath,"ar_104_01_06b.jsp",param);  

			}
		}
	}
};

