scwin.f_downExcelSheet = async function(e) {

    let options = {
        fileName : "FreightUpload",
        sheetName : "FreightUpload",
        hiddenVisible : true,
        removeColumns : "17",   //로컬 테스트용 엑셀받기 위해서
        rowNumVisible : "false"
    }

    let grdObj = gr_freightList;

    let infoArr = {};

    if(ds_freightList.getRowCount() == 0) {
        $c.win.alert(E_MSG_CM_WRN_002);
    } else {
        if(await $c.win.confirm("EXCEL로 다운로드 받으시겠습니까?")) {
            if( await $c.win.confirm(" [Yes] SAVE To CSV \n [No] Grid To Excel") ) {
                $c.data.downloadGridViewCSV(grdObj, options);
            } else {
                $c.data.downloadGridViewExcel(grdObj, options, infoArr);
            }
        }
    }

};

/**
 * 엑셀 파일 업로드
 */
scwin.f_excelUpload = async function () {

    var ext = udc_excel.getUpExt();
    var options;

	if (ext == "1") {  // xlsx, csv(1) 선택값
        var options = {
            "headerExist": "0",
            "startRowIndex": 0,
            "hidden": 1,
			"skipSpace": "1",
            "status": "C"
        };

        await $c.data.uploadGridViewCSV(gr_freightListcnt, options); // CSV를 선택하였을 경우

    } else {
        var options = {
            "headerExist": "0",
            "startRowIndex": 0,
            "hidden": 1,
			"skipSpace": "1",
            "status": "C"
        };

        await $c.data.uploadGridViewExcel(gr_freightListcnt, options); // XLSX를 선택하였을 경우

    }

};

